import { useState } from "react";
import { ClickAwayListener, Button } from "@sistent/sistent";

export function ClickAwayListenerExample() {
  const [open, setOpen] = useState(false);
  return (
    <ClickAwayListener onClickAway={() => setOpen(false)}>
      <div style={{ display: "inline-flex", flexDirection: "column", gap: "1rem" }}>
        <Button variant="contained" onClick={() => setOpen((prev) => !prev)}>
          {open ? "Close panel" : "Open panel"}
        </Button>
        {open && (
          <div
            style={{
              padding: "1rem",
              background: "#ffffff",
              border: "1px solid #d1d5db",
              borderRadius: "0.75rem",
            }}
          >
            <p style={{ margin: 0 }}>
              Clicking outside this box will close the panel.
            </p>
          </div>
        )}
      </div>
    </ClickAwayListener>
  );
}

<a id="Basic ClickAwayListener">
  <h2>Basic ClickAwayListener</h2>
</a>

ClickAwayListener monitors clicks and touches outside the wrapped element and calls the `onClickAway` callback when that happens.

<div className="showcase">
  <div className="items">
    <ThemeWrapper>
      <div style={{ display: "flex", justifyContent: "center", width: "100%" }}>
        <ClickAwayListenerExample />
      </div>
    </ThemeWrapper>
  </div>
  <CodeBlock
    name="basic-clickaway-listener"
    collapsible
    code={`import { useState } from "react";
