</div>

<a id="Custom events">
  <h2>Custom events</h2>
</a>

You can tailor when the click-away behavior triggers by configuring pointer events.

<div className="showcase">
  <div className="items">
    <CodeBlock
      name="clickaway-custom-events"
      collapsible
      code={`import { ClickAwayListener } from "@sistent/sistent";

function CustomEventsExample({ handleClose }) {
  return (
    <ClickAwayListener
      onClickAway={handleClose}
      mouseEvent="onMouseDown"
      touchEvent="onTouchEnd"
    >
      <div>Interactive content</div>
    </ClickAwayListener>
  );
}`}
    />
  </div>
</div>

<a id="Dismissible UI patterns">
  <h2>Dismissible UI patterns</h2>
</a>

ClickAwayListener is most useful for overlay patterns like dropdowns, popovers, and menus. Keep all interactive child elements inside the wrapper to avoid unintentional dismissal.

<div className="showcase">
  <div className="items">
    <CodeBlock
      name="clickaway-patterns"
      collapsible
      code={`import { useState } from "react";
import { ClickAwayListener } from "@sistent/sistent";

function DismissibleExample() {
  const [open, setOpen] = useState(false);
  return (
    <ClickAwayListener onClickAway={() => setOpen(false)}>
      <div>
        <button onClick={() => setOpen((prev) => !prev)}>Toggle menu</button>
        {open && <div>Menu content</div>}
      </div>
    </ClickAwayListener>
  );
}`}
    />
  </div>
</div>
